from pydantic import BaseModel from fastapi import FastAPI, Request from fastapi.responses import JSONResponse from pydantic import ValidationError import uuid
class ProblemDetail(BaseModel): type: str title: str status: int detail: str | None = None instance: str | None = None trace_id: str | None = None errors: list[dict] | None = None
app = FastAPI()
@app.exception_handler(ValidationError) async def validation_exception_handler(request: Request, exc: ValidationError): return JSONResponse( status_code=400, headers={"Content-Type": "application/problem+json"}, content=ProblemDetail( type="https://api.example.com/errors/validation-error", title="Validation Error", status=400, detail="Request validation failed", instance=str(request.url.path), trace_id=request.headers.get("traceparent", str(uuid.uuid4())), errors=[ {"field": e["loc"][-1], "code": e["type"], "message": e["msg"]} for e in exc.errors() ] ).model_dump() )
@app.exception_handler(Exception) async def generic_exception_handler(request: Request, exc: Exception): logger.error("Unhandled exception", exc_info=True) return JSONResponse( status_code=500, headers={"Content-Type": "application/problem+json"}, content=ProblemDetail( type="https://api.example.com/errors/internal-error", title="Internal Server Error", status=500, detail="An unexpected error occurred", instance=str(request.url.path), trace_id=request.headers.get("traceparent", str(uuid.uuid4())), ).model_dump() )

import jsonschema, requests

SCHEMA = {
    "$schema": "https://json-schema.org/draft/2020-12/schema",
    "type": "object",
    "required": ["type", "title", "status"],
    "properties": {
        "type": {"type": "string"},
        "title": {"type": "string"},
        "status": {"type": "integer", "minimum": 100, "maximum": 599},
        "detail": {"type": "string"},
        "instance": {"type": "string"},
        "traceId": {"type": "string"},
        "errors": {
            "type": "array",
            "items": {
                "type": "object",
                "required": ["field", "code", "message"],
                "properties": {
                    "field": {"type": "string"},
                    "code": {"type": "string"},
                    "message": {"type": "string"},
                }
            }
        }
    }
}

def assert_problem_detail(resp):
    assert resp.headers["content-type"].startswith("application/problem+json")
    assert 400 <= resp.status_code < 600
    jsonschema.validate(resp.json(), SCHEMA)
